<?php
namespace app\Repositories;
class SimpleRepository extends BaseRepository{ private string $table; public function __construct(string $table){parent::__construct();$this->table=$table;} public function all(string $q=''):array{return $q?$this->fetchAll("SELECT * FROM {$this->table} WHERE name LIKE ? OR type LIKE ? OR publisher LIKE ? ORDER BY id DESC",["%$q%","%$q%","%$q%"]):$this->fetchAll("SELECT * FROM {$this->table} ORDER BY id DESC");} public function find(int $id):?array{return $this->fetch("SELECT * FROM {$this->table} WHERE id=?",[$id]);} public function create(array $d):int{$this->execute("INSERT INTO {$this->table}(name,type,language,receipt_date,published_date,pages,quantity,price,publisher) VALUES(?,?,?,?,?,?,?,?,?)",[$d['name'],$d['type']??null,$d['language']??null,$d['receipt_date']??null,$d['published_date']??null,$d['pages']??0,$d['quantity']??1,$d['price']??0,$d['publisher']??null]);return $this->lastInsertId();} public function update(int $id,array $d):bool{return $this->execute("UPDATE {$this->table} SET name=?,type=?,language=?,receipt_date=?,published_date=?,pages=?,quantity=?,price=?,publisher=? WHERE id=?",[$d['name'],$d['type']??null,$d['language']??null,$d['receipt_date']??null,$d['published_date']??null,$d['pages']??0,$d['quantity']??1,$d['price']??0,$d['publisher']??null,$id]);} public function delete(int $id):bool{return $this->execute("DELETE FROM {$this->table} WHERE id=?",[$id]);}}
